INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (62, 2, "2030/01/01 14:59:59", 1, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 1000001, "カリン", "2025/01/31 12:00:00", 0.0, 1, 1, -416.5, 3.414, 190805);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (62, 2, "2030/01/01 14:59:59", 1, "ミッションをクリアして、\n報酬をゲットしましょう！", 1000002, "カリン", "2025/01/31 12:00:00", 0.0, 1, 2, -416.5, 3.099, 190805);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (63, 2, "2030/01/01 14:59:59", 1, "受け取ることができる\n報酬があるようです\n確認してみてください", 1000003, "カリン", "2025/01/31 12:00:00", 0.0, 1, 3, -416.5, 2.801, 190805);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (63, 2, "2030/01/01 14:59:59", 2, "報酬がもらえますよ！\nチェックしてみてください", 1000004, "カリン", "2025/01/31 12:00:00", 0.0, 1, 4, -416.5, 0.0, 190805);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (64, 1, "2030/01/01 14:59:59", 2, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 1000005, "カリン", "2025/01/31 12:00:00", 0.0, 1, 5, -363.0, 2.12, 190805);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (64, 2, "2030/01/01 14:59:59", 1, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 1000006, "カリン", "2025/01/31 12:00:00", 0.0, 1, 6, -363.0, 1.68, 190805);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (64, 1, "2030/01/01 14:59:59", 2, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 1000007, "カリン", "2025/01/31 12:00:00", 0.0, 1, 7, -363.0, 2.33, 190805);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 7, "2030/01/01 14:59:59", 3, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", 1020101, "ラビリスタ", "2025/01/31 12:00:00", -6.0, 10201, 101, -285.0, 5.18, 133701);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 2, "2030/01/01 14:59:59", 1, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", 1020102, "クリスティーナ", "2025/01/31 12:00:00", -2.0, 10201, 201, -285.0, 8.77, 133901);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 1, "2030/01/01 14:59:59", 6, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", 1020103, "ネネカ", "2025/01/31 12:00:00", 0.0, 10201, 301, -285.0, 15.5, 133801);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 5, "2030/01/01 14:59:59", 2, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", 1020201, "ランファ", "2025/02/28 12:00:00", 0.0, 10202, 101, -285.0, 9.061, 134301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 2, "2030/01/01 14:59:59", 1, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", 1020202, "チカ", "2025/02/28 12:00:00", 0.0, 10202, 201, -285.0, 7.699, 134401);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 2, "2030/01/01 14:59:59", 1, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", 1020301, "アオイ", "2025/03/31 12:00:00", 0.0, 10203, 101, -285.0, 8.595, 134601);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 2, "2030/01/01 14:59:59", 1, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", 1020302, "クローチェ", "2025/03/31 12:00:00", 0.0, 10203, 201, -285.0, 7.758, 134501);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 6, "2030/01/01 14:59:59", 2, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", 1020401, "ルイズマリー", "2025/04/30 12:00:00", 0.0, 10204, 101, -285.0, 7.0, 132302);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 2, "2030/01/01 14:59:59", 1, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", 1020402, "イロハ", "2025/04/30 12:00:00", 0.0, 10204, 201, -285.0, 7.904, 132402);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 2, "2030/01/01 14:59:59", 4, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", 1020403, "ソノ", "2025/04/30 12:00:00", 0.0, 10204, 301, -285.0, 8.487, 132502);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 2, "2030/01/01 14:59:59", 1, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", 1020502, "カノン", "2025/05/31 12:00:00", 0.0, 10205, 101, -285.0, 8.763, 134901);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 3, "2030/01/01 14:59:59", 1, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", 1020503, "ツムギ", "2025/05/31 12:00:00", 0.0, 10205, 201, -285.0, 6.417, 134801);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 7, "2030/01/01 14:59:59", 3, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", 1020601, "エリス", "2025/06/30 12:00:00", 0.0, 10206, 101, -285.0, 10.335, 135001);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 4, "2030/01/01 14:59:59", 2, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", 1020602, "シェフィ", "2025/06/30 12:00:00", 0.0, 10206, 201, -285.0, 6.281, 135101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 2, "2030/01/01 14:59:59", 1, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", 1020603, "プレシア", "2025/06/30 12:00:00", 0.0, 10206, 301, -285.0, 12.244, 135201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 8, "2030/01/01 14:59:59", 2, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", 1020701, "クリア", "2025/07/31 12:00:00", 0.0, 10207, 101, -285.0, 6.339, 135301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 9, "2030/01/01 14:59:59", 7, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", 1020702, "アネモネ", "2025/07/31 12:00:00", 0.0, 10207, 201, -285.0, 8.184, 135401);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 2, "2030/01/01 14:59:59", 9, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", 1020801, "アイラ", "2025/08/31 12:00:00", 0.0, 10208, 101, -285.0, 3.906, 129101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 2, "2030/01/01 14:59:59", 1, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", 1020802, "シナツ", "2025/08/31 12:00:00", 0.0, 10208, 201, -285.0, 14.465, 129201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 3, "2030/01/01 14:59:59", 4, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", 1020803, "ヒヨリ", "2025/08/31 12:00:00", 0.0, 10208, 301, -285.0, 8.662, 100101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 3, "2030/01/01 14:59:59", 1, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", 1020804, "レイ", "2025/08/31 12:00:00", 0.0, 10208, 401, -285.0, 10.915, 100301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 7, "2030/01/01 14:59:59", 1, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", 1020901, "ユキノ", "2025/09/30 12:00:00", 0.0, 10209, 101, -285.0, 6.042, 135802);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 1, "2030/01/01 14:59:59", 4, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", 1020902, "サツキ", "2025/09/30 12:00:00", 0.0, 10209, 201, -285.0, 9.402, 135903);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 1, "2030/01/01 14:59:59", 8, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", 1020903, "ルルィ", "2025/09/30 12:00:00", 0.0, 10209, 301, -285.0, 8.16, 136902);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 2, "2030/01/01 14:59:59", 3, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", 1021001, "カスミ", "2025/10/31 12:00:00", 0.0, 10210, 101, -285.0, 5.0, 137401);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 1, "2030/01/01 14:59:59", 4, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", 1021002, "アラクネ", "2025/10/31 12:00:00", 0.0, 10210, 201, -285.0, 8.12, 136001);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 2, "2030/01/01 14:59:59", 4, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", 1021003, "ナーナ", "2025/10/31 12:00:00", 0.0, 10210, 301, -285.0, 6.386, 136202);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 4, "2030/01/01 14:59:59", 3, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", 1021101, "ユイ", "2025/11/30 12:00:00", 0.0, 10211, 101, -285.0, 7.438, 136402);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 5, "2030/01/01 14:59:59", 1, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", 1021102, "ミソラ", "2025/11/30 12:00:00", 0.0, 10211, 201, -285.0, 8.35, 136302);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 2, "2030/01/01 14:59:59", 1, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", 1021201, "シズル", "2025/12/31 12:00:00", 0.0, 10212, 101, -285.0, 5.0, 136501);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 2, "2030/01/01 14:59:59", 1, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", 1021202, "リノ", "2025/12/31 12:00:00", 0.0, 10212, 201, -285.0, 5.25, 137902);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 2, "2030/01/01 14:59:59", 1, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", 1021203, "ラビリスタ", "2025/12/31 12:00:00", 0.0, 10212, 301, -285.0, 7.5, 106801);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 2, "2030/01/01 14:59:59", 1, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", 1021301, "ライラエル", "2026/01/31 12:00:00", 0.0, 10213, 101, -285.0, 8.204, 126501);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 2, "2030/01/01 14:59:59", 1, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", 1021302, "ネフィ＝ネラ", "2026/01/31 12:00:00", 0.0, 10213, 201, -285.0, 7.176, 129701);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 5, "2030/01/01 14:59:59", 1, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", 1021303, "ヴァイオレット", "2026/01/31 12:00:00", 0.0, 10213, 301, -285.0, 8.602, 133101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 3, "2030/01/01 14:59:59", 1, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", 1021304, "ライラエル", "2026/02/06 12:00:00", 0.0, 10213, 102, -285.0, 10.14, 138101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 7, "2030/01/01 14:59:59", 1, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", 1021305, "ネフィ＝ネラ", "2026/02/06 12:00:00", 0.0, 10213, 202, -285.0, 10.152, 138201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 3, "2030/01/01 14:59:59", 4, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", 1021306, "ヴァイオレット", "2026/02/06 12:00:00", 0.0, 10213, 302, -285.0, 9.688, 138001);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 1, "2030/01/01 14:59:59", 2, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", 1021307, "ペコリーヌ", "2026/02/12 12:00:00", 0.0, 10213, 401, -285.0, 5.928, 138301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 2, "2030/01/01 14:59:59", 4, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", 1021401, "ワカナ", "2026/02/28 12:00:00", 0.0, 10214, 101, -285.0, 9.19, 138702);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (61, 3, "2030/01/01 14:59:59", 1, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", 1021402, "シオリ", "2026/02/28 12:00:00", 0.0, 10214, 201, -285.0, 8.724, 138802);
